suspend fun generateResponse(
    model: GenerativeModel, prompt: String
): AiResult {
    return try {
        val response = model.generateContent(prompt)
        val text = response.text
        if (text.isNullOrBlank()) AiResult.Error("Empty response")
        else AiResult.Success(text)
    } catch (e: IOException) {
        AiResult.Error("Network error: check your connection")
    } catch (e: Exception) {
        AiResult.Error("Error: ${e.message}")
    }
}

